import React, { useState, useEffect, useCallback } from 'react';
import TableTemplate from '../components/TableTemplate';
import FormTemplate from '../components/FormTemplate';
import SearchComponent from '../components/SearchComponent';
import { vehicleService } from '../api/vehicleService';

function VehiclePage() {
  const service = vehicleService;

  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [isEditing, setIsEditing] = useState(false);
  const [currentEntity, setCurrentEntity] = useState(service.initialFormState);
  const [currentId, setCurrentId] = useState(null);
  const [authorities, setAuthorities] = useState([]);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const records = await service.getAll();
      setData(records);

      const authorityResponse = await fetch('http://localhost:3000/authority');
      const authorityData = await authorityResponse.json();
      setAuthorities(authorityData);
    } catch (err) {
      setError(`Failed to fetch ${service.name} data.`);
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [service]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleSave = async (formData, isEditMode, id) => {
    try {
      if (formData.Authority_ID && formData.Authority_ID !== '') {
        const authorityExists = authorities.some(
          (authority) =>
            authority.Authority_ID === parseInt(formData.Authority_ID)
        );
        if (!authorityExists) {
          setError(
            `Authority ID ${formData.Authority_ID} does not exist. Please enter a valid Authority ID or leave empty.`
          );
          return;
        }
      }

      setError(null);

      if (isEditMode) {
        await service.update(id, formData);
      } else {
        await service.add(formData);
      }

      fetchData();
      handleCancelEdit();
    } catch (err) {
      let errorMessage = `Failed to ${
        isEditMode ? 'update' : 'add'
      } ${service.name} record.`;

      if (err.response?.data?.message) {
        if (err.response.data.message.includes('foreign key constraint')) {
          errorMessage =
            'Invalid Authority ID. Authority_ID must reference an existing Authority.';
        } else {
          errorMessage = err.response.data.message;
        }
      } else if (err.message) {
        errorMessage = err.message;
      }

      setError(errorMessage);
      console.error(err);
    }
  };

  const handleDelete = async (id) => {
    if (
      !window.confirm(
        `Are you sure you want to delete ${service.name} ID ${id}?`
      )
    )
      return;

    try {
      await service.remove(id);
      fetchData();
    } catch (err) {
      setError(
        `Failed to delete ${service.name} record. Check for dependent records.`
      );
      console.error(err);
    }
  };

  const handleEdit = (item) => {
    setIsEditing(true);
    const itemData = { ...item };

    if (itemData.Installation_Date) {
      itemData.Installation_Date = new Date(itemData.Installation_Date)
        .toISOString()
        .split('T')[0];
    }

    setCurrentEntity(itemData);
    setCurrentId(item[service.entityIdKey]);
  };

  const handleCancelEdit = () => {
    setIsEditing(false);
    setCurrentEntity(service.initialFormState);
    setCurrentId(null);
  };

  if (loading) {
    return (
      <div className="dashboard-page">
        <div className="loading-state">
          ⏳ Loading {service.name} data...
        </div>
      </div>
    );
  }

  return (
    <div className="dashboard-page">
      {/* Page Header */}
      <div className="page-header">
        <div className="page-header-icon">🚛</div>
        <h1 className="page-title">{service.name}</h1>
        <p className="page-subtitle">
          Manage vehicle records and linked authorities efficiently
        </p>
      </div>

      {/* Error */}
      {error && <div className="alert alert-error">⚠️ {error}</div>}

      {/* Search */}
      <SearchComponent
        entityName={service.name}
        entityIdKey={service.entityIdKey}
        onSearch={service.getOne}
        onEdit={handleEdit}
        onDelete={handleDelete}
      />

      {/* Form */}
      <FormTemplate
        fields={service.fields}
        initialData={currentEntity}
        onSave={handleSave}
        isEditing={isEditing}
        entityId={currentId}
        onCancelEdit={handleCancelEdit}
      />

      {/* Table */}
      <h2 className="section-title">All {service.name} Records</h2>

      <TableTemplate
        data={data}
        columns={service.columns}
        entityIdKey={service.entityIdKey}
        onEdit={handleEdit}
        onDelete={handleDelete}
      />
    </div>
  );
}

export default VehiclePage;
